import{_ as a,o,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"MailYou Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"legal/privacy-policy.md","filePath":"legal/privacy-policy.md","lastUpdated":1773655718000}'),r={name:"legal/privacy-policy.md"};function l(n,e,s,c,d,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="mailyou-privacy-policy" tabindex="-1">MailYou Privacy Policy <a class="header-anchor" href="#mailyou-privacy-policy" aria-label="Permalink to &quot;MailYou Privacy Policy&quot;">​</a></h1><p>Effective date: 2026-03-16</p><p>This Privacy Policy applies to the MailYou desktop application and its related OAuth sign-in capabilities. MailYou is a desktop email client designed to help users connect to and manage email accounts on their local devices.</p><p>If you use Gmail, Google account sign-in, or any capability powered by Google APIs, this policy also applies to how MailYou accesses, uses, stores, shares, and deletes Google user data.</p><h2 id="_1-information-we-process" tabindex="-1">1. Information We Process <a class="header-anchor" href="#_1-information-we-process" aria-label="Permalink to &quot;1. Information We Process&quot;">​</a></h2><p>MailYou may process the following categories of information:</p><ul><li>Account information: email address, display name, provider type, server settings, protocol type, and sync preferences.</li><li>Authentication information: OAuth access tokens, refresh tokens, or the email password / app password you provide.</li><li>Mail data: message headers, senders, recipients, subjects, bodies, attachments, folders, and message state such as read/unread or starred.</li><li>Contact data: contact information and avatars that you create, import, edit, or store in MailYou.</li><li>Local app data: application settings, local caches, logs, and local data required for sync, sending mail, and draft storage.</li></ul><h2 id="_2-how-we-use-information" tabindex="-1">2. How We Use Information <a class="header-anchor" href="#_2-how-we-use-information" aria-label="Permalink to &quot;2. How We Use Information&quot;">​</a></h2><p>MailYou uses the information above only for the following purposes:</p><ul><li>Connecting to your email accounts and completing authentication.</li><li>Fetching, displaying, searching, sending, saving, and syncing email.</li><li>Maintaining local drafts, contacts, account settings, and app preferences.</li><li>Refreshing OAuth tokens to keep authorized accounts signed in.</li><li>Troubleshooting issues, improving compatibility, and maintaining desktop app stability.</li></ul><p>We do not use your Google user data or email content for advertising, profiling, selling data, or any purpose unrelated to MailYou&#39;s core functionality.</p><h2 id="_3-google-user-data-access-and-use" tabindex="-1">3. Google User Data Access and Use <a class="header-anchor" href="#_3-google-user-data-access-and-use" aria-label="Permalink to &quot;3. Google User Data Access and Use&quot;">​</a></h2><p>When you choose to connect Gmail through a Google account, MailYou accesses only the data required to provide email client functionality after you explicitly authorize it.</p><p>For Google user data, MailYou follows these principles:</p><ul><li>Access is limited to the scope required to support Gmail mail access, account connection, and token refresh.</li><li>Use is limited to the functionality explicitly requested by the user.</li><li>Google user data is not sold to third parties.</li><li>Google user data is not used for advertising, including personalized advertising.</li><li>Google user data is not shared with data brokers.</li></ul><p>MailYou&#39;s use and transfer of information received from Google APIs will adhere to the Google API Services User Data Policy, including the Limited Use requirements.</p><h2 id="_4-how-data-is-stored" tabindex="-1">4. How Data Is Stored <a class="header-anchor" href="#_4-how-data-is-stored" aria-label="Permalink to &quot;4. How Data Is Stored&quot;">​</a></h2><p>MailYou operates with a local-first model. Most account settings, mail caches, contacts, drafts, and app preferences are stored locally on your device by default.</p><p>For OAuth flows:</p><ul><li>If you use direct local OAuth, authentication is completed using provider credentials configured in your local environment variables.</li><li>If you use the MailYou OAuth proxy, the proxy is used only for required steps such as generating the authorization URL, exchanging tokens, and refreshing tokens.</li></ul><h2 id="_5-role-of-the-oauth-proxy" tabindex="-1">5. Role of the OAuth Proxy <a class="header-anchor" href="#_5-role-of-the-oauth-proxy" aria-label="Permalink to &quot;5. Role of the OAuth Proxy&quot;">​</a></h2><p>When you use the MailYou OAuth proxy, the proxy may temporarily process:</p><ul><li>OAuth provider identifier</li><li>Authorization code</li><li>PKCE-related parameters</li><li>Access tokens and refresh tokens</li></ul><p>This information is used only to complete authorization, token exchange, or token refresh, and is not used for advertising, analytics, profiling, or unrelated purposes.</p><h2 id="_6-data-sharing-and-disclosure" tabindex="-1">6. Data Sharing and Disclosure <a class="header-anchor" href="#_6-data-sharing-and-disclosure" aria-label="Permalink to &quot;6. Data Sharing and Disclosure&quot;">​</a></h2><p>We do not proactively share your personal data or Google user data with third parties except in the following cases:</p><ul><li>To interact with your chosen email provider or OAuth provider in order to complete the sign-in, mail sync, or token refresh process you requested.</li><li>To interact with the MailYou OAuth proxy if you choose to use the proxy flow.</li><li>When required by law, regulation, legal process, or a valid government request.</li><li>When necessary to protect the rights, safety, or legitimate interests of users, developers, or the public.</li></ul><h2 id="_7-data-retention-and-deletion" tabindex="-1">7. Data Retention and Deletion <a class="header-anchor" href="#_7-data-retention-and-deletion" aria-label="Permalink to &quot;7. Data Retention and Deletion&quot;">​</a></h2><p>You can delete your data in the following ways:</p><ul><li>Delete accounts, contacts, drafts, or related local data within MailYou.</li><li>Delete the application&#39;s local data directory.</li><li>Revoke MailYou&#39;s OAuth access in your Google account security settings.</li></ul><p>After you delete an account or local data, MailYou will no longer continue using the related local data. If you granted Google OAuth access, you can also revoke that access through Google&#39;s permission management tools.</p><h2 id="_8-data-security" tabindex="-1">8. Data Security <a class="header-anchor" href="#_8-data-security" aria-label="Permalink to &quot;8. Data Security&quot;">​</a></h2><p>We use reasonable technical and organizational measures to protect data, including:</p><ul><li>Local-first storage to reduce unnecessary remote transmission.</li><li>Processing data only when needed for authentication, sync, sending mail, and related core functions.</li><li>Limiting OAuth token usage to email client functionality.</li></ul><p>However, no software, transmission method, or local device can guarantee absolute security.</p><h2 id="_9-children-s-privacy" tabindex="-1">9. Children&#39;s Privacy <a class="header-anchor" href="#_9-children-s-privacy" aria-label="Permalink to &quot;9. Children&#39;s Privacy&quot;">​</a></h2><p>MailYou is not directed to children and is not intended to knowingly collect personal information from children.</p><h2 id="_10-policy-updates" tabindex="-1">10. Policy Updates <a class="header-anchor" href="#_10-policy-updates" aria-label="Permalink to &quot;10. Policy Updates&quot;">​</a></h2><p>We may update this Privacy Policy based on product changes, legal requirements, or changes in Google API policy. The updated version will be published publicly and will take effect on the new effective date.</p><h2 id="_11-contact" tabindex="-1">11. Contact <a class="header-anchor" href="#_11-contact" aria-label="Permalink to &quot;11. Contact&quot;">​</a></h2><p>If you have any questions about this Privacy Policy, or would like to contact us regarding access, deletion, or correction of data, please email:</p><p><code>4hhhhfor@gmail.com</code></p>',42)])])}const y=a(r,[["render",l]]);export{p as __pageData,y as default};
